C++<pre><code>#include&lt;bits/stdc++.h&gt;
#define Maxn 1000000
using namespace std;
int a[Maxn+5];
void down(int l,int r)
{
    int p=l,c=(l&lt;&lt;1)+1;
    while(c&lt;=r)
    {
        if(c&lt;r&amp;&amp;a[c]&lt;a[c+1]) c++;
        if(a[p]&gt;=a[c]) return ;
        else
        {
            swap(a[p],a[c]);
            p=c;
            c=(p&lt;&lt;1)+1;
        }
    }
}
void hpsort(int len)
{
    for(int i=(len-2)&gt;&gt;1;i&gt;=0;i--) down(i,len-1);
    for(int i=len-1;i&gt;0;i--)
    {
        swap(a[0],a[i]);
        down(0,i-1);
    }
}
int main()
{
