        int y=tr[x].s[0];
        if(tr[y].size+tr[x].cnt&lt;k)
        {
            k-=tr[y].size+tr[x].cnt;
            x=tr[x].s[1];
        }
        else
        {
            if(tr[y].size&gt;=k) x=y;
            else break;
        }
    }
    splay(x,0);
    return tr[x].v;
}
