        tr[p&lt;&lt;1|1].sum+=(tr[p&lt;&lt;1|1].r-tr[p&lt;&lt;1|1].l+1)*k;
        tr[p&lt;&lt;1].lazy+=k;
        tr[p&lt;&lt;1|1].lazy+=k;
        tr[p].lazy=0;
    }
